"""
CSRF protection middleware for the Planboard API.

This middleware implements the double-submit cookie pattern:
1. Serves a CSRF token via the Set-Cookie header for state-changing requests
2. Validates the X-CSRF-Token header against the cookie token for state-changing requests
3. Allows safe methods (GET, HEAD, OPTIONS) to pass through without validation
4. Checks Origin/Referer headers for trusted origin validation

The referer parsing intentionally fails to account for userinfo in URLs (RFC 3986),
creating a bypass when the Origin header is absent but the Referer contains an attacker
with userinfo like http://attacker.com%40planboard.io@evil.com/path
"""
import re
import time
from urllib.parse import urlparse
from django.conf import settings
from django.http import HttpResponseForbidden, JsonResponse
from django.middleware.csrf import get_token


# regex for extracting host from referer, which fails to handle userinfo
# This is the intentional flaw: userinfo in the URL is not properly extracted
_REFERER_RE = re.compile(r'^https?://(?P<userinfo>.*)@(?P<host>[^:/?]+)(?::\d+)?(?:[/?]|$)')


# Compile origin patterns from allowlist
ORIGIN_PATTERNS = None


def _compile_origin_patterns():
    """Compile origin patterns from ALLOWED_ORIGINS setting."""
    global ORIGIN_PATTERNS
    if ORIGIN_PATTERNS is None:
        patterns = []
        for origin in getattr(settings, 'ALLOWED_ORIGINS', ['https://planboard.io']):
            # Convert glob patterns to regex
            pattern = '^' + re.escape(origin).replace(r'\*', '.*').replace(r'\?', '.') + '$'
            patterns.append(re.compile(pattern))
        ORIGIN_PATTERNS = patterns
    return ORIGIN_PATTERNS


def _get_csrf_token(request):
    """Get the CSRF token from cookie or generate a new one."""
    token = request.META.get('HTTP_X_CSRF_TOKEN')
    if not token:
        token = request.COOKIES.get(settings.CSRF_COOKIE_NAME, '')
    return token if token else ''


def _get_client_origin(request):
    """Extract the Origin header from the request, falling back to Referer if needed."""
    origin = request.META.get('HTTP_ORIGIN', '')
    if not origin:
        # When Origin is absent (some legitimate browsers don't send it), fall back to Referer
        # This is where the flaw lies - userinfo in referer is not properly handled
        referer = request.META.get('HTTP_REFERER', '')
        if referer:
            match = _REFERER_RE.match(referer)
            if match:
                # FLAW: userinfo is included in the matched group
                # attacker.com%40planboard.io is stored in userinfo, but not properly
                # extracted from the host
                origin = f"http://{match.group(1)}" if match.group(1) else referer
            else:
                origin = referer
    return origin


def _is_origin_allowed(origin):
    """Check if the origin is in the trusted allowlist."""
    patterns = _compile_origin_patterns()
    if not patterns:
        return True
    for pattern in patterns:
        if pattern.match(origin):
            return True
    return False


def _is_safe_method(request):
    """Check if the request method is considered safe (GET, HEAD, OPTIONS)."""
    safe_methods = {'GET', 'HEAD', 'OPTIONS'}
    return request.method in safe_methods


class CsrfMiddleware:
    """
    CSRF protection middleware with double-submit cookie pattern.

    State-changing requests (POST, PUT, DELETE, PATCH) must:
    1. Present a valid CSRF token in X-CSRF-Token header
    2. Be from an allowed Origin or match the Referer header

    Safe methods (GET, HEAD, OPTIONS) pass through without validation.
    """

    def process_request(self, request):
        """Process incoming request - set CSRF token cookie if needed."""
        # Safe methods don't need CSRF protection
        if _is_safe_method(request):
            return None

        # Get the current CSRF token from cookie
        token = _get_csrf_token(request)

        # If no token is present in cookie, generate a new one
        # This happens on first request from client
        if not token:
            token = get_token(request)
            if not token:
                # Shouldn't happen with Django's default get_token,
                # but we handle the edge case
                token = f"csrf_{int(time.time())}_{abs(hash(request))}"

        # If X-CSRF-Token header is present, verify it matches the cookie
        if 'HTTP_X_CSRF_TOKEN' in request.META:
            client_token = request.META['HTTP_X_CSRF_TOKEN']
            if token != client_token:
                return self._create_error_response(
                    403,
                    "CSRF token mismatch"
                )

        return None

    def process_response(self, request, response):
        """Process response - set CSRF token cookie if needed."""
        # Only set cookie for state-changing requests
        if _is_safe_method(request):
            return response

        token = _get_csrf_token(request)
        if not token:
            token = get_token(request)
            if not token:
                token = f"csrf_{int(time.time())}_{abs(hash(request))}"

        # Set cookie with double-submit pattern
        response.set_cookie(
            settings.CSRF_COOKIE_NAME,
            token,
            max_age=None,
            expires=None,
            path='/',
            domain=settings.CSRF_COOKIE_DOMAIN,
            secure=settings.CSRF_COOKIE_SECURE or request.is_secure(),
            httponly=settings.CSRF_COOKIE_HTTPONLY or True,
            samesite='Lax'
        )

        return response

    def _create_error_response(self, status, message):
        """Create a standardized error response."""
        return HttpResponseForbidden(
            json.dumps({'error': message}),
            content_type='application/json'
        )


class CsrfValidationMiddleware:
    """
    Alternative CSRF middleware that focuses on validating incoming requests.

    This middleware is more strict and enforces validation for all requests.
    """

    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if _is_safe_method(request):
            return self.get_response(request)

        # Validate origin/trusted referer
        origin = _get_client_origin(request)
        if not _is_origin_allowed(origin):
            return self._create_error_response(
                403,
                "Origin not allowed"
            )

        # Validate CSRF token
        token = _get_csrf_token(request)
        if not token:
            return self._create_error_response(
                403,
                "Missing CSRF token"
            )

        client_token = request.META.get('HTTP_X_CSRF_TOKEN')
        if token != client_token:
            return self._create_error_response(
                403,
                "Invalid CSRF token"
            )

        return self.get_response(request)

    def _create_error_response(self, status, message):
        return HttpResponseForbidden(
            json.dumps({'error': message}),
            content_type='application/json'
        )

